func HasApprovedByUserWith(preds ...predicate.User) predicate.FinancialReversal {
	return predicate.FinancialReversal(func(s *sql.Selector) {
		step := newApprovedByUserStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.FinancialReversal) predicate.FinancialReversal {
	return predicate.FinancialReversal(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.FinancialReversal) predicate.FinancialReversal {
	return predicate.FinancialReversal(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.FinancialReversal) predicate.FinancialReversal {
	return predicate.FinancialReversal(sql.NotPredicates(p))
}
